import { Router } from "express";
import { requireAuth } from "../middleware/auth.js";
import { asyncHandler } from "../utils/asyncHandler.js";
import * as notificationController from "../controllers/notification.controller.js";
const router = Router();
router.use(requireAuth);
router.get("/", asyncHandler(notificationController.listNotifications));
router.get("/summary", asyncHandler(notificationController.getSummary));
router.patch("/:notificationId/read", asyncHandler(notificationController.markRead));
router.post("/read-all", asyncHandler(notificationController.markAllRead));
export default router;
